#Requires -Version 5.1
<#
    NullCord - graphical installer (WinForms)

    A windowed, on-brand installer (no console window) that downloads the latest NullCord build
    from GitHub Releases and patches the Discord desktop client. Compiled to NullCord-Installer.exe
    by CI with `ps2exe -noConsole`.

    The file is saved as UTF-8 WITH BOM on purpose: the UI is localized (EN/DE/ES/FR/RU) and
    Windows PowerShell 5.1 only parses non-ASCII string literals correctly when the BOM is present.

    The pixel headline font is "Jersey 15" (SIL Open Font License), embedded as Base64 and loaded
    through a PrivateFontCollection so nothing has to be installed.

    NOTE: the GitHub repo must be PUBLIC for the download to work (private-repo release assets are
    not publicly downloadable).
#>

Add-Type -AssemblyName System.Windows.Forms
Add-Type -AssemblyName System.Drawing

# Native helpers: per-process DPI awareness (crisp on 125%/150% displays instead of blurry
# bitmap stretching) and a dark window titlebar to match the dark UI. Both are best-effort;
# if compilation fails the installer still works, just without these niceties.
$script:nativeOk = $false
try {
    Add-Type -Namespace NullCordNative -Name Win32 -MemberDefinition @'
[DllImport("shcore.dll")] public static extern int SetProcessDpiAwareness(int value);
[DllImport("dwmapi.dll")] public static extern int DwmSetWindowAttribute(IntPtr hwnd, int attr, ref int value, int size);
[DllImport("user32.dll")] public static extern bool ReleaseCapture();
[DllImport("user32.dll")] public static extern IntPtr SendMessage(IntPtr hWnd, int msg, int wParam, int lParam);
'@
    $script:nativeOk = $true
} catch { }
if ($script:nativeOk) {
    # 1 = system DPI aware. Must run before the first window (incl. message boxes) is created.
    try { [void][NullCordNative.Win32]::SetProcessDpiAwareness(1) } catch { }
}

# Dark color table for the language dropdown menu (best-effort; falls back to the default look).
$script:darkMenuOk = $false
try {
    Add-Type -ReferencedAssemblies System.Windows.Forms, System.Drawing -TypeDefinition @'
using System;
using System.Drawing;
using System.Drawing.Imaging;
using System.Windows.Forms;
public class NullCordMenuColors : ProfessionalColorTable {
    public Color Bg = Color.FromArgb(33, 21, 28);
    public Color Sel = Color.FromArgb(72, 45, 60);
    public Color Bd = Color.FromArgb(64, 40, 53);
    public override Color ToolStripDropDownBackground { get { return Bg; } }
    public override Color ImageMarginGradientBegin { get { return Bg; } }
    public override Color ImageMarginGradientMiddle { get { return Bg; } }
    public override Color ImageMarginGradientEnd { get { return Bg; } }
    public override Color MenuItemSelected { get { return Sel; } }
    public override Color MenuItemBorder { get { return Sel; } }
    public override Color MenuBorder { get { return Bd; } }
}
public static class NullCordImaging {
    public static Bitmap HueShift(Image src, float delta) {
        Bitmap bmp = new Bitmap(src.Width, src.Height, PixelFormat.Format32bppArgb);
        using (Graphics g = Graphics.FromImage(bmp)) { g.DrawImage(src, 0, 0, src.Width, src.Height); }
        BitmapData d = bmp.LockBits(new Rectangle(0, 0, bmp.Width, bmp.Height), ImageLockMode.ReadWrite, PixelFormat.Format32bppArgb);
        int bytes = Math.Abs(d.Stride) * bmp.Height;
        byte[] px = new byte[bytes];
        System.Runtime.InteropServices.Marshal.Copy(d.Scan0, px, 0, bytes);
        for (int i = 0; i < bytes; i += 4) {
            float b = px[i] / 255f;
            float gc = px[i + 1] / 255f;
            float r = px[i + 2] / 255f;
            float max = Math.Max(r, Math.Max(gc, b));
            float min = Math.Min(r, Math.Min(gc, b));
            if (max == min) continue;
            float l = (max + min) / 2f;
            float dlt = max - min;
            float s = l > 0.5f ? dlt / (2f - max - min) : dlt / (max + min);
            if (s < 0.15f) continue;
            float h;
            if (max == r) h = ((gc - b) / dlt + (gc < b ? 6f : 0f)) / 6f;
            else if (max == gc) h = ((b - r) / dlt + 2f) / 6f;
            else h = ((r - gc) / dlt + 4f) / 6f;
            h = h + delta / 360f;
            h = h - (float)Math.Floor(h);
            float q = l < 0.5f ? l * (1f + s) : l + s - l * s;
            float p = 2f * l - q;
            px[i] = (byte)Math.Round(HueToRgb(p, q, h - 1f / 3f) * 255f);
            px[i + 1] = (byte)Math.Round(HueToRgb(p, q, h) * 255f);
            px[i + 2] = (byte)Math.Round(HueToRgb(p, q, h + 1f / 3f) * 255f);
        }
        System.Runtime.InteropServices.Marshal.Copy(px, 0, d.Scan0, bytes);
        bmp.UnlockBits(d);
        return bmp;
    }
    private static float HueToRgb(float p, float q, float t) {
        if (t < 0f) t += 1f;
        if (t > 1f) t -= 1f;
        if (t < 1f / 6f) return p + (q - p) * 6f * t;
        if (t < 1f / 2f) return q;
        if (t < 2f / 3f) return p + (q - p) * (2f / 3f - t) * 6f;
        return p;
    }
}
'@
    $script:darkMenuOk = $true
} catch { }

function Set-DarkTitlebar([IntPtr]$hwnd) {
    if (-not $script:nativeOk) { return }
    try {
        $on = 1
        # 20 = DWMWA_USE_IMMERSIVE_DARK_MODE (Win10 20H1+), 19 = same attribute on older builds
        [void][NullCordNative.Win32]::DwmSetWindowAttribute($hwnd, 20, [ref]$on, 4)
        [void][NullCordNative.Win32]::DwmSetWindowAttribute($hwnd, 19, [ref]$on, 4)
        # 33 = DWMWA_WINDOW_CORNER_PREFERENCE, 2 = rounded (Win11; older builds ignore it)
        $round = 2
        [void][NullCordNative.Win32]::DwmSetWindowAttribute($hwnd, 33, [ref]$round, 4)
    } catch { }
}

# The window is borderless, so dragging anywhere on the background moves it.
function Start-WindowDrag {
    if (-not $script:nativeOk) { return }
    try {
        [void][NullCordNative.Win32]::ReleaseCapture()
        [void][NullCordNative.Win32]::SendMessage($form.Handle, 0xA1, 2, 0)
    } catch { }
}

[System.Windows.Forms.Application]::EnableVisualStyles()
$ProgressPreference = "SilentlyContinue"
try {
    [Net.ServicePointManager]::SecurityProtocol = [Net.ServicePointManager]::SecurityProtocol -bor [Net.SecurityProtocolType]::Tls12 -bor [Net.SecurityProtocolType]::Tls13
} catch {
    [Net.ServicePointManager]::SecurityProtocol = [Net.ServicePointManager]::SecurityProtocol -bor [Net.SecurityProtocolType]::Tls12
}

# UI scale factor: the layout below is designed in 96-dpi units and multiplied by the real
# screen DPI through S(), so the window looks identical (but sharp) on every scaling level.
$script:ui = 1.0
try {
    $g0 = [System.Drawing.Graphics]::FromHwnd([IntPtr]::Zero)
    $script:ui = [double]$g0.DpiX / 96.0
    $g0.Dispose()
} catch { }
function S([double]$v) { return [int][Math]::Round($v * $script:ui) }

# ----- config -----
$Repo        = "NullCord-Production/NullCord"
$AsarUrl     = "https://github.com/$Repo/releases/latest/download/desktop.asar"
$InstallDir  = Join-Path $env:LOCALAPPDATA "NullCord"
$AsarPath    = Join-Path $InstallDir "desktop.asar"
$AsarForward = ($AsarPath -replace '\\', '/')

