    $g.SmoothingMode = "AntiAlias"
    $col = $cPanel
    if ($script:rowHover[[int]$s.Tag]) { $col = $cPanel2 }
    $b = New-Object System.Drawing.SolidBrush ($col)
    $path = New-RoundedPath 0 0 ($s.Width - 1) ($s.Height - 1) (S 10)
    $g.FillPath($b, $path)
    $b.Dispose(); $path.Dispose()
}
$rowEnter = {
    param($s, $e)
